    49				const currentIndex = entries.findIndex(
    50					(e) => e.provider === currentModel.provider && e.model === currentModel.id,
    51				);
    52	
    53				if (currentIndex === -1) continue;
    54	
    55				// Try entries after the current one (already sorted by priority)
    56				const result = await this._findAvailableInChain(chainName, entries, currentIndex + 1);
    57				if (result) return result;
    58	
    59				// Wrap around: try entries before the current one
    60				const wrapResult = await this._findAvailableInChain(chainName, entries, 0, currentIndex);
    61				if (wrapResult) return wrapResult;
    62			}
