import { existsSync } from "node:fs";
import { delimiter, join } from "node:path";

function isBinaryInPath(binary: string): boolean {
	const extensions = process.platform === "win32"
		? (process.env.PATHEXT ?? ".EXE;.CMD;.BAT;.COM").split(";")
		: [""];
	return (process.env.PATH ?? "")
		.split(delimiter)
		.some((dir) => dir && extensions.some((ext) => existsSync(join(dir, `${binary}${ext}`))));
}

function buildAnthropicOAuthRemovedMessage(): string {
	if (isBinaryInPath("claude")) {
		return (
			`Removed stale Anthropic OAuth credentials from auth.json. ` +
			`Anthropic OAuth is no longer supported. ` +
			`The Claude Code CLI was detected in PATH; switch this model's provider to "claude-code" to use it.`
		);
	}

	return (
		`Removed stale Anthropic OAuth credentials from auth.json. ` +
		`No API key found for "anthropic". ` +
		`Set an API key environment variable or run '/login anthropic'.`
	);
}

